// ── Validate & structure incoming complaint payload ────────────
// Paste the full script from preprocess.md Section 1

const raw = $input.first().json;

// Required field check
const required = ['incidentDate', 'healthFacility', 'complaintDetails'];
const missing  = required.filter(f => !raw[f] || raw[f].toString().trim() === '');
if (missing.length > 0) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}

// complaintDetails minimum length
if (raw.complaintDetails.trim().length < 30) {
  throw new Error('Complaint details too short (minimum 30 characters).');
}

// Email format validation (only if email provided)
if (raw.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(raw.email)) {
  throw new Error('Invalid email format: ' + raw.email);
}

// Date not in future
const incidentDate = new Date(raw.incidentDate);
if (incidentDate > new Date()) {
  throw new Error('Incident date cannot be in the future.');
}

// Pre-map issueType to broader category (assists AI)
const categoryMap = {
  'clinical-care':  'health', 'medical-staff': 'health',
  'patient-safety': 'health', 'medications':   'health',
  'billing':        'administrative', 'scheduling':  'administrative',
  'admin-staff':    'administrative', 'facility':    'administrative'
};
const preCategory = categoryMap[raw.issueType] || 'unknown';

return [{
  json: {
    ...raw,
    preCategory,
    processedAt: new Date().toISOString()
  }
}];

// Parse AI Agent output and merge with original complaint fields
const original = $('Code — Validate & Structure').first().json;
const aiRaw    = $input.first().json.output || $input.first().json.text || '';

let aiResult = {};
try {
  // Strip any accidental markdown fences before parsing
  const cleaned = aiRaw.replace(/```json|```/g, '').trim();
  aiResult = JSON.parse(cleaned);
} catch (e) {
  // Fallback — AI output could not be parsed; log and continue
  console.error('AI JSON parse error:', e.message);
  aiResult = {
    reformulated:  original.complaintDetails,
    category:      original.preCategory !== 'unknown' ? original.preCategory : 'unclassified',
    missingFields: [],
    priority:      'medium',
    aiSummary:     'AI processing failed — manual review required.'
  };
}

return [{
  json: {
    // Identity fields
    caseNumber:         original.caseNumber,
    submissionDateTime: original.submissionDateTime,
    anonymous:          original.anonymous,
    fullName:           original.fullName          || '',
    personalId:         original.personalId        || '',
    phone:              original.phone             || '',
    email:              original.email             || '',
    followUp:           original.followUp          || 'no',
    // Incident fields
    incidentDate:       original.incidentDate,
    incidentTime:       original.incidentTime      || '',
    healthFacility:     original.healthFacility,
    department:         original.department        || '',
    issueType:          original.issueType         || '',
    staffInvolved:      original.staffInvolved     || '',
    // Complaint
    complaintDetails:   original.complaintDetails,
    // AI output
    reformulated:       aiResult.reformulated      || original.complaintDetails,
    aiCategory:         aiResult.category          || 'unclassified',
    missingFields:      (aiResult.missingFields    || []).join(', '),
    priority:           aiResult.priority          || 'medium',
    aiSummary:          aiResult.aiSummary         || '',
    // Tracking
    status:             'New',
    processedAt:        original.processedAt
  }
}];

